import{j as e}from"./react-Do47R0Jx.js";import{q as o,a as r}from"./index-QaenIp61.js";import{L as a}from"./react-router-7P1i1jB-.js";import"./react-dom-DdNfKKeH.js";import"./scheduler-CvJLRKX9.js";import"./@capacitor-DsQOoex5.js";import"./clsx-B-dksMZM.js";import"./tailwind-merge-CPcsbTWB.js";import"./@supabase-BqFCU5jw.js";import"./iceberg-js-BaAu_ATF.js";import"./tslib-Ci5FaxOL.js";import"./adhan-pLRbvzC1.js";import"./lucide-react-NOfOFOSW.js";import"./framer-motion-BhJ8PfiV.js";import"./motion-dom-Cwn3fGx8.js";import"./motion-utils-CYU-yiCP.js";import"./zustand-B8yYCAIZ.js";const n={en:{title:"Privacy Policy",updated:"Last updated: March 29, 2026",intro:`At ${o.brand.en}, available at ${window.location.host}, one of our top priorities is the privacy of our visitors. This Privacy Policy document outlines the types of information we collect, how it is used, and how we protect your data in compliance with international standards, including Google AdSense requirements.`,sections:[{title:"1. Information We Collect",body:"We collect several types of information to provide and improve our services. This includes: (a) Personal Data such as name and email when you register. (b) Log Files including IP addresses, browser type, ISP, and date/time stamps. (c) User Content such as posts and comments submitted to our community platforms."},{title:"2. Cookies and Web Beacons",body:`Like any other website, Islamic Light uses "cookies" to store information including visitors' preferences, and the pages on the website that the visitor accessed or visited. The information is used to optimize the users' experience by customizing our web page content based on visitors' browser type and/or other information.`},{title:"3. Google DoubleClick DART Cookie",body:"Google is one of the third-party vendors on our site. It also uses cookies, known as DART cookies, to serve ads to our site visitors based upon their visit to our site and other sites on the internet. However, visitors may choose to decline the use of DART cookies by visiting the Google ad and content network Privacy Policy at the following URL: https://policies.google.com/technologies/ads"},{title:"4. Third-Party Privacy Policies",body:"Our Privacy Policy does not apply to other advertisers or websites. Thus, we are advising you to consult the respective Privacy Policies of these third-party ad servers for more detailed information. It may include their practices and instructions about how to opt-out of certain options. You can choose to disable cookies through your individual browser options."},{title:"5. GDPR and CCPA Protection Rights",body:"We would like to make sure you are fully aware of all of your data protection rights. Every user is entitled to the following: The right to access, the right to rectification, the right to erasure, the right to restrict processing, and the right to object to processing. If you make a request, we have one month to respond to you."},{title:"6. Children's Information",body:"Another part of our priority is adding protection for children while using the internet. We encourage parents and guardians to observe, participate in, and/or monitor and guide their online activity. Islamic Light does not knowingly collect any Personal Identifiable Information from children under the age of 13."},{title:"7. Consent",body:`By using our website, you hereby consent to our Privacy Policy and agree to its Terms and Conditions. For any privacy-related inquiries, please contact us at ${o.supportEmail}.`}],back:"Back to Home"},ar:{title:"سياسة الخصوصية",updated:"آخر تحديث: 29 مارس 2026",intro:`في ${o.brand.shortAr}، المتاحة عبر ${window.location.host}، ندرك تماماً أهمية خصوصية زوارنا. توضح وثيقة سياسة الخصوصية هذه أنواع المعلومات التي نجمعها، وكيفية استخدامها، وكيفية حماية بياناتك وفقاً للمعايير العالمية، بما في ذلك متطلبات Google AdSense.`,sections:[{title:"1. المعلومات التي نجمعها",body:"نجمع أنواعاً مختلفة من المعلومات لتحسين خدماتنا، بما في ذلك: (أ) البيانات الشخصية مثل الاسم والبريد عند التسجيل. (ب) ملفات السجل التي تشمل عناوين IP ونوع المتصفح وتاريخ الزيارة. (ج) محتوى المستخدم مثل المنشورات والتعليقات في المجتمع."},{title:"2. ملفات تعريف الارتباط (Cookies)",body:'مثل أي موقع ويب آخر، يستخدم "النور الإسلامي" ملفات تعريف الارتباط لتخزين معلومات تفضيلات الزوار والصفحات التي تمت زيارتها. تُستخدم هذه المعلومات لتحسين تجربة المستخدم من خلال تخصيص محتوى صفحة الويب بناءً على نوع متصفح الزوار ومعلومات أخرى.'},{title:"3. ملف تعريف الارتباط Google DoubleClick DART",body:"تعد Google أحد البائعين الخارجيين على موقعنا. تستخدم ملفات تعريف الارتباط DART لعرض الإعلانات لزوار موقعنا بناءً على زيارتهم لموقع إسلاميك لايت ومواقع أخرى على الإنترنت. يمكن للزوار اختيار رفض استخدام ملفات تعريف الارتباط DART من خلال زيارة سياسة خصوصية إعلانات Google وشبكة المحتوى على الرابط التالي: https://policies.google.com/technologies/ads"},{title:"4. سياسات خصوصية الطرف الثالث",body:"لا تنطبق سياسة الخصوصية الخاصة بنا على المعلنين أو المواقع الإلكترونية الأخرى. لذا، ننصحك باستشارة سياسات الخصوصية الخاصة بخوادم إعلانات الطرف الثالث للحصول على معلومات أكثر تفصيلاً حول ممارساتهم وكيفية إلغاء الاشتراك في خيارات معينة عبر إعدادات متصفحك."},{title:"5. حقوق حماية البيانات (GDPR & CCPA)",body:"نريد التأكد من أنك مدرك تماماً لجميع حقوق حماية البيانات الخاصة بك. يحق لكل مستخدم: حق الوصول، حق التصحيح، حق المسح، حق تقييد المعالجة، وحق الاعتراض على المعالجة. إذا قدمت طلباً، فلدينا شهر واحد للرد عليك."},{title:"6. معلومات الأطفال",body:'جزء من أولويتنا هو توفير الحماية للأطفال أثناء استخدام الإنترنت. نحن نشجع الآباء والأوصياء على مراقبة وتوجيه نشاطهم عبر الإنترنت. لا يجمع "النور الإسلامي" عن عمد أي معلومات تعريف شخصية من الأطفال دون سن 13 عاماً.'},{title:"7. الموافقة",body:`باستخدام موقعنا، فإنك توافق بموجب ذلك على سياسة الخصوصية الخاصة بنا وتوافق على شروطها وأحكامها. للاستفسارات المتعلقة بالخصوصية، يرجى التواصل معنا عبر: ${o.supportEmail}`}],back:"العودة للرئيسية"}},C=({lang:s})=>{const t=n[s];return e.jsx("div",{className:"min-h-screen bg-app-bg pt-32 pb-20",children:e.jsx("div",{className:"container mx-auto px-6",children:e.jsxs("div",{className:r("mx-auto max-w-4xl rounded-[2rem] border border-white/10 bg-app-card p-8 md:p-12",s==="ar"&&"text-right"),children:[e.jsx("h1",{className:"mb-2 text-4xl font-serif text-app-text",children:t.title}),e.jsx("p",{className:"mb-8 text-sm text-app-muted text-app-accent/80 font-bold uppercase tracking-widest",children:t.updated}),e.jsx("p",{className:"mb-10 leading-relaxed text-app-text/90 italic border-l-4 border-app-accent pl-6 py-2 bg-app-accent/5 rounded-r-xl",children:t.intro}),e.jsx("div",{className:"space-y-12",children:t.sections.map(i=>e.jsxs("section",{className:"relative group",children:[e.jsx("div",{className:"absolute -left-4 top-0 h-full w-1 bg-app-accent/10 group-hover:bg-app-accent transition-colors duration-500 rounded-full"}),e.jsxs("h2",{className:"mb-4 text-xl font-bold text-app-text flex items-center gap-3",children:[e.jsx("span",{className:"text-app-accent",children:"●"})," ",i.title]}),e.jsx("p",{className:"leading-relaxed text-app-muted text-base pl-2",children:i.body})]},i.title))}),e.jsxs("div",{className:"mt-16 pt-8 border-t border-white/5 flex justify-between items-center",children:[e.jsxs(a,{to:"/",className:"inline-flex items-center gap-2 text-sm font-bold text-app-accent hover:underline px-6 py-3 bg-app-accent/10 rounded-2xl transition-all hover:bg-app-accent/20",children:["← ",t.back]}),e.jsx("div",{className:"text-app-muted text-[10px] uppercase tracking-widest opacity-30",children:"AdSense Compliant v2.0"})]})]})})})};export{C as PrivacyPolicyPage};
